	if m == nil {
		m = http.NewServeMux()
	}
	if options.ErrorHandlerFunc == nil {
		options.ErrorHandlerFunc = func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusBadRequest)
		}
	}

	wrapper := ServerInterfaceWrapper{
		Handler:            si,
		HandlerMiddlewares: options.Middlewares,
		ErrorHandlerFunc:   options.ErrorHandlerFunc,
	}

	m.HandleFunc("GET "+options.BaseURL+"/health", wrapper.GetHealth)
	m.HandleFunc("GET "+options.BaseURL+"/leaderboards/current", wrapper.GetLeaderboard)
	m.HandleFunc("POST "+options.BaseURL+"/sessions", wrapper.Login)
	m.HandleFunc("DELETE "+options.BaseURL+"/sessions/current", wrapper.Logout)
	m.HandleFunc("GET "+options.BaseURL+"/users", wrapper.ListUsers)
	m.HandleFunc("POST "+options.BaseURL+"/users", wrapper.Register)
	m.HandleFunc("GET "+options.BaseURL+"/users/self", wrapper.GetCurrentUser)
	m.HandleFunc("PATCH "+options.BaseURL+"/users/self", wrapper.UpdateAvatar)
	m.HandleFunc("GET "+options.BaseURL+"/users/self/head-to-heads/{userID}", wrapper.GetHeadToHead)
	m.HandleFunc("GET "+options.BaseURL+"/users/self/stats", wrapper.GetMyStats)
	m.HandleFunc("GET "+options.BaseURL+"/users/{userID}", wrapper.GetUser)
	m.HandleFunc("GET "+options.BaseURL+"/users/{userID}/stats", wrapper.GetUserStats)
	m.HandleFunc("POST "+options.BaseURL+"/wordle-submissions", wrapper.SubmitWordle)
	m.HandleFunc("GET "+options.BaseURL+"/wordles", wrapper.GetArchive)
	m.HandleFunc("GET "+options.BaseURL+"/wordles/{wordleID}", wrapper.GetArchiveWordle)

